#!/usr/bin/perl

use strict;
use warnings;
use CGI qw(:standard);
use URI::Escape;

my $cgi = new CGI;
my $next = $cgi->param('next');

my $redirect_url = '';

if ($next && $next =~ /^https?:\/\//) {
    $redirect_url = $next;
} else {
    $redirect_url = '/';
}

print "Location: " . uri_escape($redirect_url) . "\n\n";